module RefModule(
    input clk,
    input reset_n,
    input shift,
    input d,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
        if (!reset_n) begin
            // Asynchronous reset: Reset the register to 8'b00000000
            q <= 8'b00000000;
        end else if (shift) begin
            // Shift operation: Shift left by one bit and input d
            q <= {q[6:0], d};
        end
    end

endmodule
